#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

int max(int a, int b) { return a > b ? a : b; }

int robLinear(int *arr, int start, int end) {
    int len = end - start + 1;
    if (len == 1) return arr[start];
    int prev2 = arr[start];
    int prev1 = max(arr[start], arr[start + 1]);
    for (int i = start + 2; i <= end; ++i) {
        int cur = max(prev1, prev2 + arr[i]);
        prev2 = prev1;
        prev1 = cur;
    }
    return prev1;
}

int calculateMaxRobAmount(int *houseMoneyList, int n) {
    if (n == 1) return houseMoneyList[0];
    if (n == 2) return max(houseMoneyList[0], houseMoneyList[1]);
    int exclLast = robLinear(houseMoneyList, 0, n - 2);
    int exclFirst = robLinear(houseMoneyList, 1, n - 1);
    return max(exclLast, exclFirst);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char line[5000];
