import java.io.*;
import java.util.*;

public class Main {
    private static int robLinear(int[] a, int l, int r) {
        if (l == r) return a[l];
        int prev2 = a[l];
        int prev1 = Math.max(a[l], a[l+1]);
        for (int i = l+2; i <= r; i++) {
            int cur = Math.max(prev1, prev2 + a[i]);
            prev2 = prev1;
            prev1 = cur;
        }
        return prev1;
    }

    private static int calculateMaxRobAmount(int[] houses) {
        int n = houses.length;
        if (n == 1) return houses[0];
        if (n == 2) return Math.max(houses[0], houses[1]);
        int exclLast = robLinear(houses, 0, n-2);
        int exclFirst = robLinear(houses, 1, n-1);
        return Math.max(exclLast, exclFirst);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
