        while (T-- > 0) {
            String line = br.readLine();
            List<Integer> list = new ArrayList<>();
            int num = 0; boolean in = false;
            for (char c : line.toCharArray()) {
                if (Character.isDigit(c)) { num = num*10 + (c - '0'); in = true; }
                else { if (in) { list.add(num); num = 0; in = false; } }
            }
            if (in) list.add(num);
            int[] arr = new int[list.size()];
            for (int i = 0; i < arr.length; i++) arr[i] = list.get(i);
            System.out.println(calculateMaxRobAmount(arr));
        }
    }
}

