import sys, re

def rob_linear(arr, l, r):
    if l == r:
        return arr[l]
    prev2 = arr[l]
    prev1 = max(arr[l], arr[l+1])
    for i in range(l+2, r+1):
        cur = max(prev1, prev2 + arr[i])
        prev2, prev1 = prev1, cur
    return prev1

def calculate_max(arr):
    n = len(arr)
    if n == 1:
        return arr[0]
    if n == 2:
        return max(arr[0], arr[1])
    excl_last = rob_linear(arr, 0, n-2)
    excl_first = rob_linear(arr, 1, n-1)
    return max(excl_last, excl_first)

data = sys.stdin.read().strip().split('\n')
if not data:
    sys.exit()
T = int(data[0].strip())
out_lines = []
for i in range(1, T+1):
    line = data[i]
    nums = list(map(int, re.findall(r'\d+', line)))
    out_lines.append(str(calculate_max(nums)))
print('\n'.join(out_lines))

